      "duration": 0.1
    },
    {
      "keystrokes": "ls -l /tmp/testsetgid/testfile\n",
      "duration": 0.1
    },
    {
      "keystrokes": "rm -rf /tmp/testsetgid\n",
      "duration": 0.1
    }
  ],
  "task_complete": false
}

